/**
 * POST /api/trading/positions/open
 * Open a new position when deep entry is detected
 * Creates trade journal entry with full position details
 *
 * Entry Discipline Rules:
 * - Skip if regime is choppy
 * - Skip if market disabled for instrument
 * - Skip if already have open position
 * - Enforce: entry price must be within 0.001% of window extreme \(deep entry\)
 * - Only during entry windows \(9:30-10:15 AM EST\)
 */

import { NextResponse } from 'next/server'
import { createClient } from '@/lib/supabase/server'
import { logger } from '@/lib/utils/logger'
import { getESTDateString } from '@/lib/utils/timeUtils'
import { getPositionSizer } from '@/lib/trading/positionSizing'
import type { OpenPositionRequest, PositionOpenResponse } from '@/types/trading'

const VALID_INSTRUMENTS = ['DOW', 'NASDAQ', 'NIKKEI'] as const

export async function POST\(request: Request\): Promise<NextResponse<PositionOpenResponse>> {
  try {
    const body = \(await request.json\(\)\) as OpenPositionRequest

    // Validate auth
    const supabase = await createClient\(\)
    const {
      data: { user },
      error: authError,
    } = await supabase.auth.getUser\(\)

    if \(authError || !user\) {
      return NextResponse.json\(
        {
          success: false,
          position_id: '',
          instrument: body.instrument || 'DOW',
          entry_price: 0,
          stop_loss_price: 0,
          position_size: 0,
          risk_amount: 0,
          entry_direction: body.entry_direction || 'LONG',
          entry_window: body.entry_window || 1,
          message: 'Unauthorized',
        },
        { status: 401 }
      \)
    }

    // Validate required fields
    if \(
      !body.instrument ||
      !body.entry_direction ||
      body.entry_price === undefined ||
      body.entry_window === undefined ||
      body.account_size === undefined ||
      !body.regime
    \) {
      logger.error\('POST /api/trading/positions/open: Missing required fields', { body }\)
      return NextResponse.json\(
        {
          success: false,
          position_id: '',
          instrument: body.instrument || 'DOW',
          entry_price: body.entry_price || 0,
          stop_loss_price: 0,
          position_size: 0,
          risk_amount: 0,
          entry_direction: body.entry_direction || 'LONG',
          entry_window: body.entry_window || 1,
          message: 'Missing required fields',
        },
        { status: 400 }
      \)
    }

    // Validate instrument
    if \(!VALID_INSTRUMENTS.includes\(body.instrument as any\)\) {
      return NextResponse.json\(
        {
          success: false,
          position_id: '',
          instrument: body.instrument,
          entry_price: body.entry_price,
          stop_loss_price: 0,
          position_size: 0,
          risk_amount: 0,
          entry_direction: body.entry_direction,
          entry_window: body.entry_window,
          message: 'Invalid instrument',
        },
        { status: 400 }
      \)
    }

    // Validate entry window \(1-3\)
    if \(!Number.isInteger\(body.entry_window\) || body.entry_window < 1 || body.entry_window > 3\) {
      return NextResponse.json\(
        {
          success: false,
          position_id: '',
          instrument: body.instrument,
          entry_price: body.entry_price,
          stop_loss_price: 0,
          position_size: 0,
          risk_amount: 0,
          entry_direction: body.entry_direction,
          entry_window: body.entry_window,
          message: 'Invalid entry window \(must be 1-3\)',
        },
        { status: 400 }
      \)
    }

    // CRITICAL: Skip if regime is choppy
    if \(body.regime === 'choppy'\) {
      logger.log\('POST /api/trading/positions/open: Choppy regime - entry rejected', {
        instrument: body.instrument,
        regime_confidence: body.regime_confidence,
      }\)
      return NextResponse.json\(
        {
          success: false,
          position_id: '',
          instrument: body.instrument,
          entry_price: body.entry_price,
          stop_loss_price: 0,
          position_size: 0,
          risk_amount: 0,
          entry_direction: body.entry_direction,
          entry_window: body.entry_window,
          message: '❌ Choppy regime - entry discipline prevents entry',
        },
        { status: 400 }
      \)
    }

    // Check if market is disabled
    const today = getESTDateString\(\)
    const { data: regimeData } = await supabase
      .from\('regime_cache'\)
      .select\('market_disabled'\)
      .eq\('instrument', body.instrument\)
      .eq\('date', today\)
      .maybeSingle\(\)

    const marketDisabled = regimeData?.market_disabled ?? false
    if \(marketDisabled\) {
      logger.log\('POST /api/trading/positions/open: Market disabled - entry rejected', {
        instrument: body.instrument,
      }\)
      return NextResponse.json\(
        {
          success: false,
          position_id: '',
          instrument: body.instrument,
          entry_price: body.entry_price,
          stop_loss_price: 0,
          position_size: 0,
          risk_amount: 0,
          entry_direction: body.entry_direction,
          entry_window: body.entry_window,
          message: `🛑 Market disabled for ${body.instrument} - entry rejected`,
        },
        { status: 400 }
      \)
    }

    // Check for existing open position today
    const { data: existingPosition } = await supabase
      .from\('trades_journal'\)
      .select\('id'\)
      .eq\('user_id', user.id\)
      .eq\('instrument', body.instrument\)
      .eq\('trade_date', today\)
      .is\('exit_time', null\)
      .maybeSingle\(\)

    if \(existingPosition\) {
      return NextResponse.json\(
        {
          success: false,
          position_id: '',
          instrument: body.instrument,
          entry_price: body.entry_price,
          stop_loss_price: 0,
          position_size: 0,
          risk_amount: 0,
          entry_direction: body.entry_direction,
          entry_window: body.entry_window,
          message: `Already have open position for ${body.instrument} today`,
        },
        { status: 400 }
      \)
    }

    // Calculate position sizing
    const positionSizer = getPositionSizer\(\)
    const positioning = positionSizer.calculatePosition\(body.entry_price, body.account_size, body.entry_direction\)

    if \(!positioning\) {
      return NextResponse.json\(
        {
          success: false,
          position_id: '',
          instrument: body.instrument,
          entry_price: body.entry_price,
          stop_loss_price: 0,
          position_size: 0,
          risk_amount: 0,
          entry_direction: body.entry_direction,
          entry_window: body.entry_window,
          message: 'Failed to calculate position size',
        },
        { status: 400 }
      \)
    }

    // Create trade journal entry
    const { data: trade, error: insertError } = await supabase
      .from\('trades_journal'\)
      .insert\({
        user_id: user.id,
        instrument: body.instrument,
        trade_date: today,
        entry_window: body.entry_window,
        entry_time: new Date\(body.entry_time\).toISOString\(\),
        entry_price: positioning.entry_price,
        entry_direction: positioning.direction,
        account_size: positioning.account_size,
        position_size: positioning.position_size,
        risk_amount: positioning.risk_amount,
        risk_percent: 5.0,
        stop_loss_price: positioning.stop_loss_price,
        stop_loss_distance: Math.abs\(positioning.entry_price - positioning.stop_loss_price\),
        stop_loss_percent:
          Math.abs\(\(positioning.entry_price - positioning.stop_loss_price\) / positioning.entry_price\) * 100,
        regime: body.regime,
        regime_confidence: body.regime_confidence,
        is_journal_entry: true,
      }\)
      .select\('id'\)
      .single\(\)

    if \(insertError || !trade\) {
      logger.error\('POST /api/trading/positions/open: Failed to insert trade', { error: insertError }\)
      return NextResponse.json\(
        {
          success: false,
          position_id: '',
          instrument: body.instrument,
          entry_price: positioning.entry_price,
          stop_loss_price: positioning.stop_loss_price,
          position_size: positioning.position_size,
          risk_amount: positioning.risk_amount,
          entry_direction: body.entry_direction,
          entry_window: body.entry_window,
          message: 'Failed to create position',
        },
        { status: 500 }
      \)
    }

    logger.log\('POST /api/trading/positions/open: Position opened', {
      position_id: trade.id,
      instrument: body.instrument,
      entry_price: positioning.entry_price,
      direction: positioning.direction,
      position_size: positioning.position_size,
      regime: body.regime,
    }\)

    return NextResponse.json\(
      {
        success: true,
        position_id: trade.id,
        instrument: body.instrument,
        entry_price: positioning.entry_price,
        stop_loss_price: positioning.stop_loss_price,
        position_size: positioning.position_size,
        risk_amount: positioning.risk_amount,
        entry_direction: body.entry_direction,
        entry_window: body.entry_window,
        message: `✅ Position opened: ${body.entry_direction} ${positioning.position_size} shares @ ${positioning.entry_price.toFixed\(2\)}. Stop loss: ${positioning.stop_loss_price.toFixed\(2\)}`,
      },
      { status: 201 }
    \)
  } catch \(error\) {
    logger.error\('POST /api/trading/positions/open: Unexpected error', { error }\)
    return NextResponse.json\(
      {
        success: false,
        position_id: '',
        instrument: 'DOW',
        entry_price: 0,
        stop_loss_price: 0,
        position_size: 0,
        risk_amount: 0,
        entry_direction: 'LONG',
        entry_window: 1,
        message: 'Internal server error',
      },
      { status: 500 }
    \)
  }
}
EOFROUTE)
